#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int arr[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, N, sizeof(int), compare);
        for (int i = 0; i < N - 1; i++) {
            if (arr[i] == arr[i + 1]) {
                printf("%d\n", arr[i]);
                break;
            } else if (arr[i + 1] - arr[i] > 1) {
                printf("%d\n", arr[i + 1]);
                break;
            }
        }
    }
    return 0;
}

