import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            Arrays.sort(arr);
            for (int i = 0; i < N - 1; i++) {
                if (arr[i] == arr[i + 1]) {
                    System.out.println(arr[i]);
                    break;
                } else if (arr[i + 1] - arr[i] > 1) {
                    System.out.println(arr[i + 1]);
                    break;
                }
            }
        }
    }
}

